from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete (or related entities) into a fluent, single sentence."""
    if not triples:
        return ""

    # Helper mappings
    athlete_predicates = {"birthDate", "birthYear", "birthPlace", "height", "weight",
                          "position", "club", "currentclub", "formerTeam", "currentteam",
                          "debutTeam", "draftYear", "draftRound", "draftPick", "playerNumber"}
    team_predicates = {"owner", "city", "ground", "stadium"}

    # Index triples by subject for quick lookup
    by_subject: dict[str, list[Triple]] = {}
    for t in triples:
        by_subject.setdefault(t.subject, []).append(t)

    # Find primary athlete (subject that has at least one athlete‑specific predicate)
    primary_athlete = None
    for subj, ts in by_subject.items():
        if any(t.predicate in athlete_predicates for t in ts):
            primary_athlete = subj
            break

    # If no clear athlete, fall back to generic concatenation
    if not primary_athlete:
        # Simple generic rendering (similar to previous version)
        parts = []
        for t in triples:
            parts.append(f"{t.subject} {t.predicate} {t.object}")
        return "; ".join(parts) + "."

    # Gather athlete information
    athlete_info = {t.predicate: t.object for t in by_subject[primary_athlete]}

    # Helper to build a relative clause for a team
    def team_clause(team_name: str) -> str:
        clauses = []
        for t in by_subject.get(team_name, []):
            if t.predicate == "owner":
                clauses.append(f"owned by {t.object}")
            elif t.predicate == "city":
                clauses.append(f"based in {t.object}")
            elif t.predicate in {"ground", "stadium"}:
                clauses.append(f"play at {t.object}")
        if not clauses:
            return team_name
        return f"{team_name} who " + " and ".join(clauses)

    # Build sentence parts
    sentences = []

    # Debut information
    if "debutTeam" in athlete_info:
        debut = athlete_info["debutTeam"]
        sentences.append(f"{primary_athlete} made his debut with {team_clause(debut)}")

    # Former team information
    if "formerTeam" in athlete_info:
        former = athlete_info["formerTeam"]
        # Use pronoun if debut already mentioned
        pronoun = "He" if sentences else primary_athlete
        sentences.append(f"{pronoun} later played for {team_clause(former)}")

    # Current team information
    if "currentteam" in athlete_info:
        current = athlete_info["currentteam"]
        pronoun = "He" if sentences else primary_athlete
        sentences.append(f"{pronoun} currently plays for {team_clause(current)}")

    # Additional simple athlete facts (birth, height, etc.)
    simple_facts = {
        "birthDate": lambda o: f"was born on {o}",
        "birthYear": lambda o: f"was born in {o}",
        "birthPlace": lambda o: f"was born in {o}",
        "height": lambda o: f"is {o} meters tall",
        "weight": lambda o: f"weighs {o}",
        "position": lambda o: f"plays as a {o}",
        "playerNumber": lambda o: f"wears number {o}",
    }
    for pred, formatter in simple_facts.items():
        if pred in athlete_info:
            sentences.append(f"{primary_athlete} {formatter(athlete_info[pred])}")

    # Combine all parts into one fluent sentence
    if not sentences:
        return ""

    # Join with commas, using 'and' before the last clause
    if len(sentences) == 1:
        result = sentences[0]
    else:
        *head, tail = sentences
        result = ", ".join(head) + ", and " + tail

    # Ensure final punctuation
    if not result.endswith('.'):
        result += '.'
    return result

